package org.apache.commons.math.complex;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.complex.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
    // Empty class to run Cucumber tests with JUnit
}

package org.apache.commons.math.complex.steps;

import org.apache.commons.math.complex.Complex;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private Complex number1;
    private Complex number2;
    private Complex result;

    @Given("I have a complex number \\({double}, {double}\\)")
    public void i_have_a_complex_number(double real, double imag) {
        number1 = new Complex(real, imag);
    }

    @Given("I have another complex number \\({double}, {double}\\)")
    public void i_have_another_complex_number(double real, double imag) {
        number2 = new Complex(real, imag);
    }

    @When("I multiply \\({double}, {double}\\) with \\({double}, {double}\\)")
    public void i_multiply_with(double real1, double imag1, double real2, double imag2) {
        Complex num1 = new Complex(real1, imag1);
        Complex num2 = new Complex(real2, imag2);
        try {
            result = num1.multiply(num2);
        } catch (Exception e) {
            // Handle any exceptions that might occur during multiplication
            System.out.println("Exception during multiplication: " + e.getMessage());
            throw e;
        }
    }

    @When("I multiply ({word})\\+i({word}) with ({word})\\+i({word})")
    public void i_multiply_various_cases(String real1Str, String imag1Str, String real2Str, String imag2Str) {
        // Convert strings to doubles, handling special values like "inf", "-inf", "nan"
        double real1 = parseSpecialValue(real1Str);
        double imag1 = parseSpecialValue(imag1Str);
        double real2 = parseSpecialValue(real2Str);
        double imag2 = parseSpecialValue(imag2Str);

        Complex num1 = new Complex(real1, imag1);
        Complex num2 = new Complex(real2, imag2);
        try {
            result = num1.multiply(num2);
        } catch (Exception e) {
            // Handle any exceptions that might occur during multiplication
            System.out.println("Exception during multiplication: " + e.getMessage());
            throw e;
        }
    }

    @Then("the result should be \\({double}, {double}\\)")
    public void the_result_should_be(double expectedReal, double expectedImag) {
        Complex expected = new Complex(expectedReal, expectedImag);
        assertEquals("Real part should match", expectedReal, result.getReal(), 0.001);
        assertEquals("Imaginary part should match", expectedImag, result.getImaginary(), 0.001);
        assertTrue("Result should equal expected", result.equals(expected));
    }

    @Then("the result should be calculated according to complex multiplication rules")
    public void the_result_should_be_calculated_according_to_complex_multiplication_rules() {
        // This is more of a verification that the result follows the mathematical formula
        // (a + bi) * (c + di) = (ac - bd) + (ad + bc)i
        double a = number1 != null ? number1.getReal() : 0;
        double b = number1 != null ? number1.getImaginary() : 0;
        double c = number2 != null ? number2.getReal() : 0;
        double d = number2 != null ? number2.getImaginary() : 0;

        double expectedReal = a * c - b * d;
        double expectedImag = a * d + b * c;

        // Check if the actual result matches the mathematical calculation
        assertEquals(expectedReal, result.getReal(), 0.001);
        assertEquals(expectedImag, result.getImaginary(), 0.001);
    }

    private double parseSpecialValue(String str) {
        switch(str.toLowerCase()) {
            case "inf":
                return Double.POSITIVE_INFINITY;
            case "-inf":
                return Double.NEGATIVE_INFINITY;
            case "nan":
                return Double.NaN;
            default:
                return Double.parseDouble(str);
        }
    }
}

